    17→
    18→/* ------------------------------------------------------------------ */
    19→/*  Helpers                                                            */
    20→/* ------------------------------------------------------------------ */
    21→
    22→function getProviderUrl(
    23→  provider: string,
    24→  repository: string,
    25→  version: string
    26→): string | null {
    27→  switch (provider) {
    28→    case "github":
