    24→}
    25→
    26→const PER_PAGE = 15;
    27→
    28→function getProviderUrl(
    29→  provider: string,
    30→  repository: string,
    31→  version: string
    32→): string | null {
    33→  switch (provider) {
    34→    case "github":
    35→      return `https://github.com/${repository}/releases/tag/${version}`;
    36→    case "dockerhub":
    37→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    38→    default:
    39→      return null;
    40→  }
    41→}
    42→
    43→/* ------------------------------------------------------------------ */
    44→/*  Page                                                               */
    45→/* ------------------------------------------------------------------ */
    46→
    47→export default function ReleasesPage() {
    48→  return (
    49→    <Suspense>
    50→      <ReleasesPageInner />
    51→    </Suspense>
    52→  );
    53→}
    54→
    55→function ReleasesPageInner() {
    56→  const searchParams = useSearchParams();
    57→  const initialProject = searchParams.get("project") ?? "all";
    58→  const [page, setPage] = useState(1);
    59→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    60→
    61→  /* Fetch projects for the filter dropdown + source enrichment */
    62→  const { data: projectsData } = useSWR("projects-for-filter", () =>
    63→    projectsApi.list()
    64→  );
    65→
    66→  /* Build a map: sourceId -> { provider, repository, projectName, projectId } */
    67→  const { data: sourceMap } = useSWR(
    68→    projectsData ? "source-map-for-releases" : null,
    69→    async () => {
    70→      if (!projectsData?.data?.length) return new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    71→      const map = new Map<string, { provider: string; repository: string; projectName: string; projectId: string }>();
    72→      await Promise.all(
    73→        projectsData.data.map(async (p: Project) => {
    74→          const res = await sourcesApi.listByProject(p.id).catch(() => null);
    75→          if (res?.data) {
    76→            for (const s of res.data) {
    77→              map.set(s.id, {
    78→                provider: s.provider,
    79→                repository: s.repository,
    80→                projectName: p.name,
    81→                projectId: p.id,
    82→              });
    83→            }
    84→          }
    85→        })
    86→      );
    87→      return map;
    88→    }
    89→  );
