    93→    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    94→    () => releasesApi.listByProject(projectFilter, page, PER_PAGE)
    95→  );
    96→
    97→  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    98→    projectFilter === "all" ? ["all-releases", page] : null,
    99→    () => releasesApi.list(page, PER_PAGE)
   100→  );
   101→
   102→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
   103→
   104→  /* Enrich releases with source metadata */
   105→  const rawReleases: Release[] =
   106→    projectFilter !== "all"
   107→      ? scopedData?.data ?? []
   108→      : allReleasesData?.data ?? [];
