     7→  projects as projectsApi,
     8→  releases as releasesApi,
     9→  sources as sourcesApi,
    10→  semanticReleases as srApi,
    11→} from "@/lib/api/client";
    12→import { getProviderIcon } from "@/components/ui/provider-badge";
    13→import { timeAgo } from "@/lib/format";
    14→import { Plus, X, ArrowRight } from "lucide-react";
    15→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    16→import { ProjectForm } from "@/components/projects/project-form";
    17→import type { Project, Source } from "@/lib/api/types";
    18→
    19→/* ---------- Inline Add Source Form ---------- */
    20→
    21→function InlineSourceForm({
    22→  projectId,
    23→  onDone,
    24→}: {
    25→  projectId: string;
    26→  onDone: () => void;
    27→}) {
    28→  const [provider, setProvider] = useState("github");
    29→  const [repository, setRepository] = useState("");
    30→  const [pollInterval, setPollInterval] = useState("300");
    31→  const [saving, setSaving] = useState(false);
    32→  const [error, setError] = useState("");
    33→
    34→  const handleAdd = async (e: React.FormEvent) => {
    35→    e.preventDefault();
    36→    if (!repository.trim()) return;
    37→    setSaving(true);
    38→    setError("");
    39→    try {
    40→      await sourcesApi.create(projectId, {
    41→        provider,
    42→        repository: repository.trim(),
    43→        poll_interval_seconds: Number(pollInterval) || 300,
    44→        enabled: true,
    45→      });
    46→      mutate(`project-${projectId}-card-sources`);
    47→      onDone();
    48→    } catch (err: unknown) {
    49→      setError(err instanceof Error ? err.message : "Failed to add source");
    50→    } finally {
    51→      setSaving(false);
    52→    }
    53→  };
    54→
    55→  return (
    56→    <form onSubmit={handleAdd} className="mt-2 rounded-md border p-3 space-y-2" style={{ borderColor: "#e8e8e5", backgroundColor: "#fafaf9" }}>
    57→      {error && <div className="text-[12px] text-red-600">{error}</div>}
    58→      <div className="flex items-center gap-2">
    59→        <select
    60→          value={provider}
    61→          onChange={(e) => setProvider(e.target.value)}
    62→          className="rounded-md border px-2 py-1 text-[12px]"
    63→          style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)" }}
    64→        >
    65→          <option value="github">GitHub</option>
    66→          <option value="dockerhub">Docker Hub</option>
    67→        </select>
    68→        <input
    69→          type="text"
    70→          value={repository}
    71→          onChange={(e) => setRepository(e.target.value)}
    72→          placeholder="e.g. ethereum/go-ethereum"
    73→          className="flex-1 rounded-md border px-2 py-1 text-[12px]"
    74→          style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
    75→        />
    76→        <input
    77→          type="number"
    78→          min={60}
    79→          value={pollInterval}
    80→          onChange={(e) => setPollInterval(e.target.value)}
    81→          className="w-20 rounded-md border px-2 py-1 text-[12px]"
    82→          style={{ borderColor: "#e8e8e5" }}
    83→          title="Poll interval (seconds)"
    84→        />
    85→      </div>
    86→      <div className="flex items-center justify-end gap-2">
    87→        <button
    88→          type="button"
    89→          onClick={onDone}
    90→          className="text-[12px] text-[#9ca3af] hover:text-[#6b7280]"
    91→        >
    92→          Cancel
    93→        </button>
    94→        <button
    95→          type="submit"
    96→          disabled={saving || !repository.trim()}
    97→          className="rounded-md px-3 py-1 text-[12px] font-medium text-white disabled:opacity-40"
    98→          style={{ backgroundColor: "#e8601a" }}
    99→        >
   100→          {saving ? "Adding..." : "Add"}
   101→        </button>
   102→      </div>
   103→    </form>
   104→  );
   105→}
   106→
   107→/* ---------- Sources Section ---------- */
   108→
   109→function SourcesSection({ projectId }: { projectId: string }) {
   110→  const [adding, setAdding] = useState(false);
   111→  const { data } = useSWR(`project-${projectId}-card-sources`, () =>
   112→    sourcesApi.listByProject(projectId)
   113→  );
   114→  const sources = data?.data ?? [];
   115→
   116→  return (
   117→    <div className="px-4 py-3 md:border-r" style={{ borderColor: "#e8e8e5" }}>
   118→      <div className="flex items-center justify-between mb-1">
   119→        <span
   120→          className="text-[11px] font-medium uppercase tracking-[0.08em]"
   121→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   122→        >
   123→          Sources
   124→        </span>
   125→        {!adding && (
   126→          <button
   127→            onClick={() => setAdding(true)}
   128→            className="inline-flex items-center gap-1 text-[11px] font-medium transition-colors hover:opacity-80"
   129→            style={{ color: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
   130→          >
   131→            <Plus className="h-3 w-3" />
   132→            Add Source
   133→          </button>
   134→        )}
   135→        {adding && (
   136→          <button
   137→            onClick={() => setAdding(false)}
   138→            className="text-[#9ca3af] hover:text-[#6b7280]"
   139→          >
   140→            <X className="h-3.5 w-3.5" />
   141→          </button>
   142→        )}
   143→      </div>
   144→
   145→      {sources.length > 0 ? (
   146→        <div className="space-y-1">
   147→          {sources.map((source) => {
   148→            const Icon = getProviderIcon(source.provider);
   149→            return (
   150→              <div
   151→                key={source.id}
   152→                className="flex items-center gap-2 text-[12px]"
   153→                style={{ fontFamily: "var(--font-dm-sans)" }}
   154→              >
   155→                {Icon && <Icon size={13} className="shrink-0" style={{ color: "#6b7280" }} />}
   156→                <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
   157→                  {source.repository}
   158→                </span>
   159→                <span
   160→                  className="ml-auto flex items-center gap-1.5 text-[11px]"
