   617→	err := s.pool.QueryRow(ctx,
   618→		`SELECT id, project_id, semantic_release_id, trigger, status,
   619→		        COALESCE(prompt_used,''), COALESCE(error,''),
   620→		        started_at, completed_at, created_at
   621→		 FROM agent_runs WHERE id = $1`, id,
   622→	).Scan(&run.ID, &run.ProjectID, &run.SemanticReleaseID, &run.Trigger, &run.Status,
   623→		&run.PromptUsed, &run.Error, &run.StartedAt, &run.CompletedAt, &run.CreatedAt)
