   654→// GetPreviousRelease returns the most recent release for a source that is not
   655→// the given version, ordered by created_at descending. Returns nil (no error)
   656→// if no previous release exists.
   657→func (s *PgStore) GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error) {
   658→	var rel models.Release
   659→	err := s.pool.QueryRow(ctx,
   660→		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   661→		 FROM releases
   662→		 WHERE source_id = $1 AND version != $2
   663→		 ORDER BY COALESCE(released_at, created_at) DESC
   664→		 LIMIT 1`, sourceID, beforeVersion,
   665→	).Scan(&rel.ID, &rel.SourceID, &rel.Version, &rel.RawData, &rel.ReleasedAt, &rel.CreatedAt)
   666→	if err != nil {
