   675→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   676→// This follows the transactional outbox pattern for zero-loss guarantee.
   677→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger string) error {
   678→	tx, err := s.pool.Begin(ctx)
   679→	if err != nil {
   680→		return fmt.Errorf("begin tx: %w", err)
   681→	}
   682→	defer tx.Rollback(ctx)
   683→
   684→	var runID string
   685→	err = tx.QueryRow(ctx,
   686→		`INSERT INTO agent_runs (project_id, trigger, status)
   687→		 VALUES ($1, $2, 'pending')
   688→		 RETURNING id`, projectID, trigger,
   689→	).Scan(&runID)
   690→	if err != nil {
   691→		return fmt.Errorf("insert agent run: %w", err)
   692→	}
   693→
   694→	if s.river != nil {
   695→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   696→			AgentRunID: runID,
   697→			ProjectID:  projectID,
   698→		}, nil)
   699→		if err != nil {
   700→			return fmt.Errorf("enqueue agent job: %w", err)
   701→		}
   702→	}
   703→
   704→	return tx.Commit(ctx)
   705→}
