   709→// UpdateAgentRunStatus sets the status of an agent run and updates the
   710→// started_at timestamp when transitioning to "running".
   711→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   712→	var query string
   713→	switch status {
   714→	case "running":
   715→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   716→	case "completed":
   717→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   718→	default:
   719→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   720→	}
   721→	tag, err := s.pool.Exec(ctx, query, status, id)
   722→	if err != nil {
   723→		return fmt.Errorf("update agent run status: %w", err)
   724→	}
   725→	if tag.RowsAffected() == 0 {
   726→		return fmt.Errorf("agent run not found: %s", id)
   727→	}
   728→	return nil
   729→}
