   753→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   754→			sr.ID, relID,
   755→		)
   756→		if err != nil {
   757→			return fmt.Errorf("insert semantic release source: %w", err)
   758→		}
   759→	}
   760→
   761→	return tx.Commit(ctx)
   762→}
